<script>
    document.addEventListener('DOMContentLoaded', function () {
        const logo = document.getElementById('logo-button');
        const right = document.getElementById('adrRight');

        logo.addEventListener('click', () => {
            right.classList.toggle('show');
            logo.classList.toggle('active');
        });
    });
</script>
<script>
    (function () {
        const shell = document.getElementById('logo-button');
        const svg = document.getElementById('logo-svg');

        function replay() {
            // Stop glow effect after click
            shell.classList.add('no-glow');

            // Restart SVG animation
            //svg.classList.remove('play');
            void svg.offsetWidth;
            svg.classList.toggle('play');
        }

        shell.addEventListener('click', replay);
        shell.addEventListener('keydown', (e) => {
            if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); replay(); }
        });
    })();
</script>

